  if lx < gcc - ghalf {
    assert !CellInSquare(ly, lx, gcr, gcc, ghalf);
    assert lx < gcc - ghalf;
    assert lx == gcc - ghalf - 1;
  }
  assert lx == gcc - ghalf;

